var b="url",c="出库任务操作_全部类型_.html",d="generationDate",e=new Date(1781593030428.69),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="Variable_RKRW",r="NewVariable",s="page",t="packageId",u="161d5a1e585c466fa40179037487335b",v="type",w="Axure:Page",x="出库任务操作(全部类型)",y="notes",z="annotations",A="fn",B="1",C="ownerId",D="2b0949c5e5634acfa0daff5d6f0e4855",E="label",F="用料位置：",G="说明",H="<p><span>1.字段</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">展示</span><span>须满足下述全部条件</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.数据字典[system_config_agv_location_open]==1</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.当前“出库类型”为'领料出库'</span></p><p><span>2.取值：去重后逗号拼接</span></p>",I="2",J="ea8d90da8b584cf78e90ff5e5e60c086",K="物料详情",L="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">生产计划用量</span></p><p><span>1.仅出库类型为&quot;领料出库&quot;展示该列</span></p><p><span>2.热区Tooltips：通过生产订单BOM计算出SKU所需的数量</span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\"><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">专单采购</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">1.仅在出库类型为“领料出库”时展示</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">2.使用当前生产订单进行入库的数量指的是“实际入库数量”而不是首次入库数量</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">3.热区tooltips提示字：使用当前生产订单进行采购的数量/使用当前生产订单进行入库的数量</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\"><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">计划出库数</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">1.热区Tooltips：出库任务要求的出库数量</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\"><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">初始拣货</span></p><p><span>1.直接拣货：由[提交本次拣货]累计过来</span></p><p><span>2.PDA拣货：确认复核后累计</span></p><p><span>3.热区Tooltips</span><span style=\"color:#333333;\">：</span><span>初始出库数量合计</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">累计补入</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">1.</span><span>热区Tooltips</span><span style=\"color:#333333;\">：初始出库数量填错，通过批次码进行补回的数量</span></p><p><span style=\"color:#333333;\"><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">实际拣货</span></p><p><span>1.实际拣货=初始拣货-累计补入</span></p><p><span>2.热区Tooltips：实际拣货=初始拣货-累计补入</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">批次数</span></p><p><span>1.在当前</span><span style=\"text-decoration:underline ;\">出库详情</span><span>中该SKU对应，且“实际拣货”＞0的数据行数</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">待复核数</span></p><p><span>1.由pda拣货但未复核(拣货暂存区)进行累计</span></p><p><span>2.配置项system_config_wms_out_task_type=1时隐藏该列</span></p><p><span>3.热区Tooltips：在PDA上提交拣货后须复核后正式出库</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">当前锁库数量</span></p><p><span>1.跟随PDA拣货数量进行变动</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.例如本来锁库30个，当pda提交拣货5个(未复核)时就把对应的部分扣除</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.提交后，[已拣数量]=0，[待复核数]=5，[当前锁库数量]=25</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">未锁数量</span></p><p><span>1.未锁数量=计划出库数量-已拣数量-待复核数-当前锁库数量</span></p><p><span>2.若数值算出来为负数，展示为0</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">锁库推荐库位</span></p><p><span>1.锁库时刷新该列</span></p><p><span>2.解锁时清空该列</span></p><p><span>3.配置项 [ system_config_wms_out_task_type ] ==1时隐藏该列</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.出库方式：0-扫码出库 1-直接拣货 2-同时存在</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">操作【锁库】</span></p><p><span>1.未锁数量＞0时可点击，否则禁用</span></p><p><span>2.点击按照“未锁数量”进行锁库</span></p><p><span>3.根据锁库更新“锁库推荐库位”</span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">操作【解锁】</span></p><p><span>1.当前锁库数量＞0时可点击，否则禁用</span></p><p><span>2.点击后释放当前锁库数量至未锁数量</span></p><p><span>3.点击后清空“锁库推荐库位”</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">可用库存(批次数)</span></p><p><span>1.可用库存：未锁库存+当前出库单锁的库存；也就是最大可出库数量</span></p><p><span>2.批次数：未锁库存+当前出库单锁的批次码个数</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">本次出库数</span></p><p><span>1.配置项 [ system_config_wms_out_task_type ] ==0时隐藏该列</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.出库方式：0-扫码出库 1-直接拣货 2-同时存在</span></p><p><span>2.格式：限制2位小数</span></p>",M="3",N="8b916db2e6e640ff87847ff512fe617a",O="一键锁库",P="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">锁库原则</span></p><p><span>1.被绑定订单的物料，若当前出库任务不是关联对应订单，无法锁库。</span></p><p><span>2.被绑定款号的物料，若当前出库任务不是关联对应款号，无法锁库。</span></p><p><span>3.若物料没被订单、款号绑定，只要SKU-属主-仓库 保持一致即可锁库。</span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">锁库推荐顺序</span></p><p><span>1.物料为订单+款号绑定的；</span></p><p><span>2.物料为订单绑定的；</span></p><p><span>3.物料为款号绑定的；</span></p><p><span>4.单个库位满足的；如果多个仓库满足的，就近原则（库位号小）</span></p><p><span>5.拣货路径逻辑：按库位编号排序；</span></p><p><span>6.如果库存数量小于需求数量，按照库存数量锁库；</span></p>",Q="4",R="121c0c04897547b896ed44c802ab2a25",S="补单出库：",T="<p><span>1.system_config_wms_out_task_type=0时隐藏该功能字段</span></p><p><span>2.出库类型为“调拨出库”时隐藏该功能字段</span></p>",U="5",V="5bb5320ffbe446faaf5964bf4fa88fe7",W="(下拉列表)",X="<p><span>1.默认：旧批次优先</span></p><p><span>2.system_config_wms_out_task_type=0时隐藏该选项</span></p><p><span>3.可选项：</span></p><p><span>&nbsp;&nbsp; a.旧批次优先</span></p><p><span>&nbsp;&nbsp; b.新批次优先</span></p><p><span>&nbsp;&nbsp; c.批次库存少优先</span></p>",Y="6",Z="9884b997a8af4d14aac502daeaa71497",ba="计划数量",bb="<p><span>1.system_config_wms_out_task_type=0时隐藏该按钮</span></p><p><span>2.计算 </span><span style=\"color:#D9001B;\">计划出库数-实际拣货-待复核数</span><span> 数值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.数值＞0：将对应数值填充至“本次出库数”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.数值 ≤ 0：将'0'填充至“本次出库数”</span></p>",bc="7",bd="3beb4a5544a146e8ba1da79cb36be94d",be="提交本次拣货",bf="<p><span>按钮展示/隐藏</span></p><p><span>1.system_config_wms_out_task_type</span></p><p><span>&nbsp;&nbsp; a.配置项=0：隐藏</span></p><p><span>&nbsp;&nbsp; b.配置项=1：显示</span></p><p><span><br></span></p><p><span>按钮操作</span></p><p><span>1.若勾选“补单出库”，但未填写日期，提示“请选择实际出库时间”</span></p><p><span>2.【230419】依次校验单行数据是否处于盘点导致无法出库</span></p><p><span>&nbsp;&nbsp; a.校验是否存在盘点类型为</span><span style=\"color:#8400FF;\">指定库位</span><span>，盘点方式为静态盘点且审核状态为未审核的盘点单的“仓库”与当前出库任务单的</span><span style=\"color:#8400FF;\">“仓库”</span><span>一致的</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; i.若存在，Toast提示：XXX处于静态盘点，无法出库：YYY</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; ii.其中：XXX为当前仓库名称；YYY为对应查到的盘点单号</span></p><p><span>&nbsp;&nbsp; b.校验是否存在盘点类型为</span><span style=\"color:#8400FF;\">物料大类</span><span>，盘点方式为静态盘点且审核状态为未审核的盘点单的“属主-仓库”与当前出库任务单的</span><span style=\"color:#8400FF;\">“属主-仓库”</span><span>且盘点单的“物料类别”包含当前操作行的</span><span style=\"color:#8400FF;\">物料所属的物料大类</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; i.若存在，Toast提示：XXX在当前属主-仓库中处于静态盘点，无法出库：YYY</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; ii.其中：XXX为物料大类名称；YYY为对应查到的盘点单号</span></p><p><span>&nbsp;&nbsp; c.校验是否存在盘点类型为</span><span style=\"color:#8400FF;\">指定物料</span><span>，盘点方式为静态盘点且审核状态为未审核的盘点单的“属主-仓库”与当前出库任务单的</span><span style=\"color:#8400FF;\">“属主-仓库”</span><span>且盘点单的“物料编码”包含当前操作行的</span><span style=\"color:#8400FF;\">“物料编码”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; i.若存在，Toast提示：XXX在当前属主-仓库中处于静态盘点，无法出库：YYY</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; ii.其中：XXX为物料名称；YYY为对应查到的盘点单号</span></p><p><span>3.若当前出库任务是</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#45971C;\">采购退货</span><span>，对应的采购订单的结算状态为“已结算”，提示：采购订单已按退货数量结算，无法再次出库</span></p><p><span>4.【230210补充校验】若当前出库任务是</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#45971C;\">领料出库</span><span>，对应的生产订单的结案状态为“已结案”，提示：生产订单已结案，无法再次出库</span></p><p><span>5.提交拣货时，忽略[本次出库数]为0的行，无需校验</span></p><p><span>6.如果填写的数量大于可扣除的库存，提示“库存不足，无法扣除”</span></p><p><span>7.提交拣货逻辑：以绑定订单/款号的绑定关系优先原则上，若存在多个批次，先后顺序再根据选择的优先方式来(</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">旧批次优先 或 新批次优先 或 </span><span>批次库存少优先)，直接把批次数量扣除并记录至【出库详情】</span></p><p><span>顺序如下：</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; a.绑定 订单-款号 优先</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; b.绑定 订单 优先</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; c.绑定 款号 优先</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; d.无绑定关系</span></p><p><span>8.【230213补充】扣除库存的时候，根据配置项判断是否需要生成新批次码。且若当前出库任务是</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#45971C;\">领料出库</span><span>，且配置项 [ system_config_take_out_batch_code ] ==1(生成新批次)</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; a.若是批次原有库存全部出库，无须生成新批次码，同原逻辑</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; b.</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#007CFF;\">若存在某批次只出了一部分</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">，生成一个新的物料批次码</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; i.在原有的批次码上对库存进行扣除</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; ii.在 [ 出库详情 ] 中展示的批次是新生成的批次码及信息</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; iii.生成的新批次信息：批次数量为0，初始拣货数量为从原批次上扣除的部分；批次码上的其他信息都是从原批次上复制过来的(库位、用样、SKU等)</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">9.生成[出库单]数据</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">10.生成[出入库明细]数据</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">11.其它相关</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; a.重新计算 [物料仓库系统&gt;&gt;库存分析：库存查询]中相关</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#D9001B;\">属主-仓库-SKU</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">的'移动价值(未)'和'移动价值(含)'</span></p>",bg="8",bh="1168049c212b416bb5381caefebee76b",bi="完成调拨",bj="<p><span>1.仅出库类型为“调拨出库”时展示该功能按钮</span></p><p><span>2.system_config_wms_out_task_type=0时隐藏该按钮</span></p>",bk="9",bl="0cb050a5338141848e41618d881c4c81",bm="扫描批次：",bn="<p><span>1.校验该批次是否符合出库要求</span></p><p><span>&nbsp;&nbsp; &nbsp; a.库存中存在的批次码，否则Toast提示：无效的批次码</span></p><p><span>&nbsp;&nbsp; &nbsp; b.批次码所属SKU须为当前出库清单中包含的SKU，否则Toast提示：出库清单中无该物料</span></p><p><span>&nbsp;&nbsp; &nbsp; c.批次码所属的“仓库”须与当前出库任务的“出库仓库”一致，否则Toast提示：不是当前&quot;仓库&quot;的批次码</span></p><p><span>&nbsp;&nbsp; &nbsp; d.批次码所属的“属主”须与当前出库任务的“库存组织”一致，否则Toast提示：不是当前&quot;属主&quot;的批次码</span></p><p><span>&nbsp;&nbsp; &nbsp; e.若批次码绑定“订单”，须与当前出库任务的“生产订单”一致，否则Toast提示：该批次已被其他订单号绑定</span></p><p><span>&nbsp;&nbsp; &nbsp; f.若批次码绑定“款号”，须与当前出库任务的“款号”一致，否则Toast提示：该批次已被其他款号绑定</span></p><p><span>2.校验该批次码对是否处于盘点导致无法出库</span></p><p><span>&nbsp;&nbsp; a.校验是否存在盘点类型为</span><span style=\"color:#8400FF;\">指定库位</span><span>，盘点方式为静态盘点且审核状态为未审核的盘点单的“仓库”与当前出库任务单的</span><span style=\"color:#8400FF;\">“仓库”</span><span>一致的</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; i.若存在，Toast提示：XXX处于静态盘点，无法出库：YYY</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; ii.其中：XXX为当前仓库名称；YYY为对应查到的盘点单号</span></p><p><span>&nbsp;&nbsp; b.校验是否存在盘点类型为</span><span style=\"color:#8400FF;\">物料大类</span><span>，盘点方式为静态盘点且审核状态为未审核的盘点单的“属主-仓库”与当前出库任务单的</span><span style=\"color:#8400FF;\">“属主-仓库”</span><span>且盘点单的“物料类别”包含当前操作行的</span><span style=\"color:#8400FF;\">物料所属的物料大类</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; i.若存在，Toast提示：XXX在当前属主-仓库中处于静态盘点，无法出库：YYY</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; ii.其中：XXX为物料大类名称；YYY为对应查到的盘点单号</span></p><p><span>&nbsp;&nbsp; c.校验是否存在盘点类型为</span><span style=\"color:#8400FF;\">指定物料</span><span>，盘点方式为静态盘点且审核状态为未审核的盘点单的“属主-仓库”与当前出库任务单的</span><span style=\"color:#8400FF;\">“属主-仓库”</span><span>且盘点单的“物料编码”包含当前操作行的</span><span style=\"color:#8400FF;\">“物料编码”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; i.若存在，Toast提示：XXX在当前属主-仓库中处于静态盘点，无法出库：YYY</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; ii.其中：XXX为物料名称；YYY为对应查到的盘点单号</span></p><p><span>3.对出库类型为</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#3399FF;\">采购退货出库</span><span>的校验</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.校验当前出库任务对应“采购订单”的结算状态</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.未结算：通过校验</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.已结算：Toast提示“采购订单已按退货数量结算，无法再次出库”</span></p><p><span>4.对出库类型为</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#3399FF;\">领料出库</span><span>的校验</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.校验当前出库任务对应“生产订单”的结案状态</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.已结案：Toast提示“生产订单已结案，无法再次出库”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.未结案：通过校验</span></p><p><span>5.通过全部校验：弹窗填写该批次的出库数量</span></p>",bo="10",bp="b77e2128d61a4ed6973c77725fe2c107",bq="打印 ∨",br="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#45971C;\">出库报告</span></p><p><span>1.仅将批次的SKU对应为面料的批次行进行打印；忽略SKU为辅料的批次码</span></p><p><span>2.将勾选的批次码，根据SKU展示成多个清单；每个SKU一个清单</span></p><p><span>3.清单内的部分信息是找这个批次码曾在[采购入库-检验]中的数据</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#45971C;\">批次标签</span></p><p><span>1.将勾选的批次行的物料码按顺序进行打印</span></p>",bs="11",bt="5beb436f1bb94c9c9e6391d4640d45d1",bu="批次数量",bv="<p><span>当前二位码批次物料的剩余数量</span></p>",bw="12",bx="4c9e720fcb8e4a10984ae35b0d1ec8f1",by="初始拣货",bz="<p><span>累计直接拣货里提交的拣货数量</span></p>",bA="13",bB="a3ba6bf59c654b038db43aacff043ba3",bC="累计补入",bD="<p><span>累计库存补入中对应批次码的补回数量</span></p>",bE="14",bF="2ea6cbdd55b04b5697507cb32b1790be",bG="实际拣货",bH="<p><span>=初始拣货-累计补入</span></p>",bI="15",bJ="6248d3ba1b8c47969f9f24777e5d2a7e",bK="* 出库仓库：",bL="<p><span style=\"color:#333333;\">1.默认值为当前入库任务单的仓库</span></p><p><span style=\"color:#333333;\">2.可选择仓库属性：余料仓库、物料仓库、面料仓库、辅料仓库</span></p>",bM="16",bN="c7a18c2706de4f92bdb8cdb6b7e01a66",bO="确定",bP="<p><span>1. 确认后，变更当前出库任务单的出库仓库进行修改</span></p><p><span>2. 前端注意刷新当前字段值</span></p><p><span>3. 自动解锁</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i. “当前锁库数量”置0</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii. “未锁数量”=计划出库数</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; iii. “锁库推荐位置”置空</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; iv. “操作”全部变为未锁库状态，[锁库]可点击，[解锁]置灰</span></p><p><span>4. “可用库存”根据当前的 出库仓库</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i. 对 属主-出库仓库-SKU 进行重新计算</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii. 点击弹窗展示的也是也对应的批次码</span></p>",bQ="17",bR="2a6efa8d37124041ae79e5bef9138861",bS="* 属主：",bT="<p><span style=\"color:#333333;\">1.默认值为当前的属主</span></p><p><span style=\"color:#333333;\">2.可选择为系统内“属主”</span></p>",bU="18",bV="0d45181c0e81498a91889ab7d4016674",bW="<p><span>1. 确认后，对当前出库任务单的属主进行修改</span></p><p><span>2. 前端注意刷新当前字段值</span></p><p><span>3. 自动解锁</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i. “当前锁库数量”置0</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii. “未锁数量”=计划出库数</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; iii. “锁库推荐位置”置空</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; iv. “操作”全部变为未锁库状态，[锁库]可点击，[解锁]置灰</span></p><p><span>4. “可用库存”根据当前的 属主</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i. 对 属主-出库仓库-SKU 进行重新计算</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii. 点击弹窗展示的也是也对应的批次码</span></p>",bX="19",bY="67bcb5797e30438b8e9e0df2eb38250e",bZ="拣货单",ca="<p><span>以当前出库任务中的SKU清单作为唯一行</span></p>",cb="20",cc="f2bb9a3169ca434aa390ba9924376610",cd="<p><span>根据选择的打印方式及“拣货时间”查询数量</span></p><p><span>1.[总拣货]就是当前清单展示的</span></p><p><span>2.[范围拣货]需要从</span><span style=\"text-decoration:underline ;\">库存分析&gt;&gt;出入库明细</span><span>中找到时间范围内这个出库任务单(CKRW)下该SKU的</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">出库</span><span style=\"color:#02A7F0;\">及对应的</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">补入</span><span style=\"color:#02A7F0;\">记录</span><span>后计算得出</span></p>",ce="21",cf="cd7700c096e44803921989d8d1e930e3",cg="拣货时间：",ch="<p><span>[筛选拣货]：按选择的拣货时间范围（开始时间补秒'00'，结束时间补秒'59'）</span></p><p><span>[总拣货]：写死'全部'</span></p>",ci="22",cj="2f2acd8dc58e493a8ff755cdf782616b",ck="打印时间：",cl="<p><span>当前时间</span></p>",cm="23",cn="48d04b6b706f4b9ea91711ef3902ff6f",co="<p><span>按[总拣货]时，隐藏该列</span></p>",cp="24",cq="84b37ecf330042b883f6b3fb64e7c015",cr="* 拣货时间：",cs="<p><span>1.必填</span></p><p><span>2.选择时间程度：年-月-日-时-分</span></p><p><span>3.默认从</span><span style=\"color:#3399FF;\">当前时间的前五分钟</span><span>至</span><span style=\"color:#3399FF;\">当前时间</span></p>",ct="25",cu="703ad896ca1f4e69b0e36b1005e0d066",cv="<p><span>1.自动补足开始时间和结束时间的秒数</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.开始时间对应秒为‘00’</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.结束时间对应秒为‘59’</span></p><p><span>2.根据筛选的时间展示对应数据</span></p><p><span>3.根据系统配置项值 [ system_config_COMPANY_TYPE ] 进行打印预览</span></p>",cw="26",cx="38425467e9824b4eaae63ab8ef4492e5",cy="打印预览",cz="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#027DB4;\">分页</span></p><p><span>根据当前出库任务中出库清单的SKU行数拆分成多个页面</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.调整行高使一张A5纸能够容纳下</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; i.首页固定条数(待前端调整行高查看)</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; ii.其它页面均固定相同条数</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.</span><span style=\"color:#4B7902;\">仅首页</span><span>有：标题、基础信息</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; c.每页均有：清单信息、页脚</span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#027DB4;\"><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#027DB4;\">标题</span></p><p><span>1.固定写作'拣货单'</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#027DB4;\">基础信息</span></p><p><span>1.出库任务、仓库、用料单位、生产单号、款号、备注：均取自当前出库任务单的对应字段信息</span></p><p><span>2.打印时间：当前打印预览的时间</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#027DB4;\">清单信息</span></p><p><span>1.仅展示“实际拣货”＞0的行</span></p><p><span>2.取值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.物料编码、物料名称、颜色、规格/门幅、单位：均跟随对应SKU行的字段值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.实际拣货：根据选择的打印方式及“拣货时间”查询数量</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; i.[总拣货]就是当前清单展示的</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; ii.[范围拣货]需要从</span><span style=\"text-decoration:underline ;\">库存分析&gt;&gt;出入库明细</span><span>中找到时间范围内这个出库任务单(CKRW)下该SKU的</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">出库</span><span style=\"color:#4B7902;\">及对应的</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">补入</span><span style=\"color:#4B7902;\">记录</span><span>后计算得出</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; c.合计：取的数量是</span><span style=\"color:#D9001B;\">全部清单</span><span>的，而不是仅当前页的</span></p><p><span>3.样式</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.物料编码、物料名称、颜色、规格/门幅：字体居左</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.实入数量、单位：字体居右</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; i.实入数量的值</span><span style=\"color:#6300BF;\">补足两位小数</span></p><p><span>4.若当前页面的行数不足，依然保留线条，展示空白格</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#027DB4;\">页脚</span></p><p><span>1.拣货时间</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.[筛选拣货]：按选择的拣货时间范围（开始时间补秒'00'，结束时间补秒'59'）</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.[总拣货]：写死'全部'</span></p><p><span>2.制单人：当前入库任务单的创建人</span></p><p><span>3.固定字段：</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#D9001B;\">请在收到货后三个工作日内确认数量，逾期不候。</span></p><p><span>4.签收人：仅给字段标题，由线下签字</span></p><p><span>5.页码：包含当前页数和总页数</span></p>",cA="27",cB="08d253fb1ec24d87984242ce824f85cf",cC="<p><span>根据选择的打印方式及“拣货时间”查询数量</span></p><p><span>1.[总拣货]就是当前清单展示的“实际拣货”</span></p><p><span>2.[范围拣货]需要从</span><span style=\"text-decoration:underline ;\">库存分析&gt;&gt;出入库明细</span><span>中找到时间范围内这个出库任务单(CKRW)下该SKU的</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">出库</span><span style=\"color:#02A7F0;\">及对应的</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">补入</span><span style=\"color:#02A7F0;\">记录</span><span>后计算得出</span></p>",cD="28",cE="7597919425724ea3a1026c3a0b1964d5",cF="29",cG="36a3422eee48408eaa5840864ce0bb09",cH="<p><span>打印模板跟随配置项 [ system_config_COMPANY_TYPE ] </span></p>",cI="30",cJ="45e217ec558b497cab36d960991edaea",cK="上传",cL="<p><span>1.点击获取本地文件</span></p><p><span>2.上传成功后，对该物料的[物料明细]对应“物料主图”进行覆盖</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.当前弹窗刷新“物料主图”</span></p>",cM="31",cN="3b987fc0975f43d8a808a284a5efd3f2",cO="补回入库",cP="<p><span>1.【230419】校验该批次码对是否处于盘点导致无法补入</span></p><p><span>&nbsp;&nbsp; a.校验是否存在盘点类型为</span><span style=\"color:#8400FF;\">指定库位</span><span>，盘点方式为静态盘点且审核状态为未审核的盘点单的“仓库”与当前出库任务单的</span><span style=\"color:#8400FF;\">“仓库”</span><span>一致的</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; i.若存在，Toast提示：XXX处于静态盘点，无法补入：YYY</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; ii.其中：XXX为当前仓库名称；YYY为对应查到的盘点单号</span></p><p><span>&nbsp;&nbsp; b.校验是否存在盘点类型为</span><span style=\"color:#8400FF;\">物料大类</span><span>，盘点方式为静态盘点且审核状态为未审核的盘点单的“属主-仓库”与当前出库任务单的</span><span style=\"color:#8400FF;\">“属主-仓库”</span><span>且盘点单的“物料类别”包含当前操作行的</span><span style=\"color:#8400FF;\">物料所属的物料大类</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; i.若存在，Toast提示：XXX在当前属主-仓库中处于静态盘点，无法补入：YYY</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; ii.其中：XXX为物料大类名称；YYY为对应查到的盘点单号</span></p><p><span>&nbsp;&nbsp; c.校验是否存在盘点类型为</span><span style=\"color:#8400FF;\">指定物料</span><span>，盘点方式为静态盘点且审核状态为未审核的盘点单的“属主-仓库”与当前出库任务单的</span><span style=\"color:#8400FF;\">“属主-仓库”</span><span>且盘点单的“物料编码”包含当前操作行的</span><span style=\"color:#8400FF;\">“物料编码”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; i.若存在，Toast提示：XXX在当前属主-仓库中处于静态盘点，无法补入：YYY</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; ii.其中：XXX为物料名称；YYY为对应查到的盘点单号</span></p><p><span>2. 判断一下填写的“补回库存数”累计是否已经超出已拣数量（已经拣货10个，已补回2个，再次补入的时候，不能超过8个），否则提示“补回数量已超出拣货范围”</span></p><p><span>3. 通过校验</span></p><p><span>&nbsp;&nbsp; a.将补回的库存计入到批次码里</span></p><p><span>&nbsp;&nbsp; b.生成入库单(RKD)</span></p><p><span>&nbsp;&nbsp; c.以“多拣补入”为入库的类型，记录至入库明细及出入库明细中</span></p>",cQ="32",cR="7ffd8a8b562c4faf83aa948e26a02c96",cS="批次数量：",cT="<p><span>获取扫码批次的“库存数量”</span></p>",cU="33",cV="642d3eab18c146809539e5bb9d5e4ff7",cW="出库数量：",cX="<p><span>1.默认值取当前“批次数量”</span></p><p><span>2.保留两位小数</span></p><p><span>3.前端控制编辑框不得大于“批次数量”的数量</span></p>",cY="34",cZ="3e7c9116889b494b8bf46238c5a86165",da="确认",db="<p><span>1.校验“出库数量”须大于0，否则提示：出库数量须大于0</span></p><p><span>2.校验是否“出库数量”依然大于当前的“批次数量”</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.否则提示：库存不足，无法出库</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.保留当前弹窗，前端重新获取该批次的“批次数量”并更新值，重新使用获取到的“批次数量”对“出库数量”赋默认值</span></p><p><span>3.按“出库数量”的四舍五入保留两位小数，对该批次进行出库，并计入对应SKU的拣货数量中</span></p><p><span>4.【230213补充】扣除库存的时候，根据配置项判断是否需要生成新批次码。且若当前出库任务是</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#45971C;\">领料出库</span><span>，且配置项 [ system_config_take_out_batch_code ] ==1(生成新批次)</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; a.若该批次原有库存全部出库，无须生成新批次码，同原逻辑</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp;&nbsp; b.</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#007CFF;\">若存在该批次上只出了一部分</span><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">，生成一个新的物料批次码</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; i.在原有的批次码上对库存进行扣除</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; ii.在 [ 出库详情 ] 中展示的批次是新生成的批次码及信息</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;\">&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; iii.生成的新批次信息：批次数量为0，初始拣货数量为从原批次上扣除的部分；批次码上的其他信息都是从原批次上复制过来的(库位、用样、SKU等)</span></p>",dc="style",dd="baseStyle",de="627587b6038d43cca051c114ac41ad32",df="pageAlignment",dg="center",dh="fill",di="fillType",dj="solid",dk="color",dl=0xFFFFFFFF,dm="image",dn="imageAlignment",dp="near",dq="imageRepeat",dr="auto",ds="favicon",dt="sketchFactor",du="0",dv="colorStyle",dw="appliedColor",dx="fontName",dy="Applied Font",dz="borderWidth",dA="borderVisibility",dB="borderFill",dC=0xFF797979,dD="cornerRadius",dE="cornerVisibility",dF="outerShadow",dG="on",dH=false,dI="offsetX",dJ=5,dK="offsetY",dL="blurRadius",dM="spread",dN="r",dO=0,dP="g",dQ="b",dR="a",dS=0.349019607843137,dT="adaptiveStyles",dU="interactionMap"